import { Tabs, type Href, useRouter } from "expo-router";

import { ClientBottomTabBar } from "../../src/components/ClientBottomTabBar";

const keyByRoute: Record<string, "home" | "categories" | "post" | "messages" | "profile"> = {
  home: "home",
  categories: "categories",
  "post-project": "post",
  messages: "messages",
  profile: "profile"
};

const hrefByKey: Record<"home" | "categories" | "post" | "messages" | "profile", Href> = {
  home: "/tabs/home",
  categories: "/tabs/categories",
  post: "/projects/create",
  messages: "/tabs/messages",
  profile: "/tabs/profile"
};

export default function ClientTabsLayout() {
  const router = useRouter();

  return (
    <Tabs
      screenOptions={{ headerShown: false }}
      tabBar={({ state }) => (
        <ClientBottomTabBar
          activeKey={keyByRoute[state.routes[state.index]?.name] ?? "home"}
          onSelect={(key) => router.push(hrefByKey[key])}
        />
      )}
    >
      <Tabs.Screen name="home" options={{ title: "Home" }} />
      <Tabs.Screen name="categories" options={{ title: "Categories" }} />
      <Tabs.Screen name="post-project" options={{ title: "Post" }} />
      <Tabs.Screen name="messages" options={{ title: "Messages" }} />
      <Tabs.Screen name="profile" options={{ title: "Profile" }} />
    </Tabs>
  );
}

import { useRouter } from "expo-router";
import { useQuery } from "@tanstack/react-query";
import { fetchMe } from "@serrale/api";
import { clearSession } from "@serrale/auth";
import {
  AppButton,
  AppCard,
  LoadingScreen,
  ProfileAvatar,
  colors,
  spacing,
  typography
} from "@serrale/ui";
import { StyleSheet, Text, View } from "react-native";

export default function ProfileTabScreen() {
  const router = useRouter();
  const meQuery = useQuery({
    queryKey: ["client-profile"],
    queryFn: fetchMe
  });

  if (meQuery.isPending) {
    return <LoadingScreen message="Loading profile..." />;
  }

  if (meQuery.isError || !meQuery.data) {
    return (
      <View style={styles.screen}>
        <Text style={styles.error}>Unable to load profile.</Text>
      </View>
    );
  }

  return (
    <View style={styles.screen}>
      <AppCard style={styles.card}>
        <ProfileAvatar
          fullName={meQuery.data.user.full_name}
          avatarUrl={meQuery.data.user.avatar_url}
          size={56}
        />
        <Text style={styles.name}>{meQuery.data.user.full_name}</Text>
        <Text style={styles.email}>{meQuery.data.user.email}</Text>
        <AppButton label="Profile Settings" variant="secondary" onPress={() => router.push("/settings/profile")} />
        <AppButton
          label="Log Out"
          variant="danger"
          onPress={async () => {
            await clearSession();
            router.replace("/auth/login");
          }}
        />
      </AppCard>
    </View>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    backgroundColor: colors.background,
    padding: spacing.lg
  },
  card: {
    gap: spacing.sm,
    alignItems: "center"
  },
  name: {
    ...typography.h2,
    color: colors.primaryDark
  },
  email: {
    ...typography.body,
    color: colors.textMuted
  },
  error: {
    ...typography.body,
    color: colors.danger
  }
});

