export default function MessagesTabScreen() {
  const conversationsQuery = useQuery({
    queryKey: ["client-conversations"],
    queryFn: getConversations
  });

  if (conversationsQuery.isPending) {
    return <LoadingScreen message="Loading conversations..." />;
  }

  return (
    <ScrollView contentContainerStyle={styles.content}>
      <Text style={styles.title}>Messages</Text>
      {(conversationsQuery.data ?? []).map((conversation) => (
        <AppCard key={conversation.id} style={styles.card}>
          <Text style={styles.preview}>
            {conversation.last_message_preview || "Start a conversation"}
          </Text>
          <Text style={styles.meta}>{new Date(conversation.updated_at).toLocaleString()}</Text>
        </AppCard>
      ))}
    </ScrollView>
  );
}

